// Use Central Time explicitly so date is correct regardless of server TZ
const TZ = 'America/Chicago';
const now = new Date();
const fmt = (opts) => new Intl.DateTimeFormat('en-US', { timeZone: TZ, ...opts });
const year = parseInt(fmt({ year: 'numeric' }).format(now));
const month = fmt({ month: '2-digit' }).format(now);
const day = fmt({ day: '2-digit' }).format(now);
const dateStr = `${year}-${month}-${day}`;

const dayName = fmt({ weekday: 'long' }).format(now);

const janFirst = new Date(year, 0, 1);
const dayOfYear = Math.ceil((now - janFirst) / 86400000);
const weekNumber = Math.ceil((dayOfYear + janFirst.getDay()) / 7);
const weekStr = `${year}-W${String(weekNumber).padStart(2, '0')}`;

const focusThemes = {
  Monday: 'Planning & Priorities',
  Tuesday: 'Deep Work',
  Wednesday: 'Collaboration & Meetings',
  Thursday: 'Deep Work',
  Friday: 'Review & Wrap-Up',
  Saturday: 'Personal & Projects',
  Sunday: 'Rest & Reflection'
};
const focusTheme = focusThemes[dayName] || 'General';

const fileKey = `Homelab/40_Timeline_Weekly/Daily/${dateStr}.md`;

return [{ json: { dateStr, dayName, weekStr, focusTheme, fileKey, bucket: 'obsidian-vault' } }];

// Read overdue tasks and needle-movers for gate check
// We'll check the Master Task List for overdue items and Priority A tasks
const input = $input.first().json;
return [{ json: { ...input, needsContextRead: true } }];

// Gate check: parse MTL for overdue tasks and needle-movers
// If nothing interesting, skip AI call entirely
const dateInfo = $('Compute Date & File Path').first().json;
const todayStr = dateInfo.dateStr;

let mtlContent = '';
try {
  const binary = $input.first().binary;
  if (binary && binary.data) {
    mtlContent = Buffer.from(binary.data.data, 'base64').toString('utf-8');
  }
} catch (e) { /* no MTL found, that's ok */ }

// Parse overdue tasks
const taskRegex = /^\s*- \[ \]\s+(.+)$/gm;
const overdueItems = [];
const needleMovers = [];
let match;

while ((match = taskRegex.exec(mtlContent)) !== null) {
  const line = match[1];
  const dueMatch = line.match(/\[due::\s*(\d{4}-\d{2}-\d{2})\s*\]/);
  const priorityMatch = line.match(/\[priority::\s*([A-C])\s*\]/i);
  const areaMatch = line.match(/\[area::\s*(\w+)\s*\]/);

  const priority = priorityMatch ? priorityMatch[1].toUpperCase() : 'B';

  if (dueMatch && dueMatch[1] < todayStr) {
    overdueItems.push({ task: line.substring(0, 80), due: dueMatch[1], area: areaMatch ? areaMatch[1] : 'unknown', priority });
  }
  if (priority === 'A') {
    needleMovers.push({ task: line.substring(0, 80), due: dueMatch ? dueMatch[1] : null, area: areaMatch ? areaMatch[1] : 'unknown' });
  }
}

const hasSignal = overdueItems.length > 0 || needleMovers.length > 0;

return [{ json: {
  hasSignal,
  overdueItems,
  needleMovers,
  overdueCount: overdueItems.length,
  needleMoverCount: needleMovers.length
} }];

const gate = $input.first().json;
const overdueStr = gate.overdueItems.map(t => `- ${t.task} (${t.area}, ${t.priority}, due ${t.due})`).join('
');
const nmStr = gate.needleMovers.map(t => `- ${t.task} (${t.area}${t.due ? ', due ' + t.due : ''})`).join('
');

const content = `Overdue tasks (${gate.overdueCount}):
${overdueStr || 'None'}

Needle-movers this week (${gate.needleMoverCount}):
${nmStr || 'None'}`;

const SYSTEM = 'You are the AI Brain for Aaron's Life Operating System. Return structured JSON only. Be extremely concise — 50-80 words max for the entire briefing.';
const USER = `TASK: Generate a concise daily briefing.

Return JSON:
{"results": {"focus_items": ["item1", "item2", "item3"], "domain_nudge": "string|null", "overdue_count": 0}}

CONTENT:
${content}`;

return [{ json: { systemPrompt: SYSTEM, userMessage: USER } }];

const input = $input.first().json;
try {
  const content = input.choices[0].message.content;
  // Strip markdown fences if present (some models add them)
  const cleaned = content.replace(/^```json\n?/i, '').replace(/\n?```$/i, '').trim();
  const parsed = JSON.parse(cleaned);
  return [{ json: { success: true, ...parsed, source: 'openrouter' } }];
} catch (e) {
  return [{ json: { success: false, error: 'Failed to parse AI response: ' + e.message, raw: JSON.stringify(input).substring(0, 500) } }];
}

const { dateStr, dayName, weekStr, focusTheme, fileKey } = $('Compute Date & File Path').first().json;

// Try to get briefing data from AI if it ran
let briefSection = '## Today's Focus
> Set your top 3 priorities for today.

';
try {
  const briefData = $('Parse AI Response').first().json.results || $('Parse AI Response').first().json;
  if (briefData) {
    const focusItems = briefData.focus_items || [];
    const nudge = briefData.domain_nudge;
    briefSection = '## Today's Focus
';
    if (focusItems.length > 0) {
      briefSection += `> **${focusItems.length} items need attention today:**
`;
      focusItems.forEach((item, i) => {
        briefSection += `> ${i + 1}. ${item}
`;
      });
      if (nudge) {
        briefSection += `>
> *${nudge}*
`;
      }
    }
    briefSection += '
';
  }
} catch (e) { /* no briefing available, use static */ }

const content = `---
date: ${dateStr}
day: ${dayName}
week: ${weekStr}
focus_theme: "${focusTheme}"
tags:
  - daily-note
---

# ${dayName}, ${dateStr}

> **Focus Theme:** ${focusTheme}

---

${briefSection}---

## Top 3 Priorities

- [ ] [area:: work] [priority:: A]
- [ ] [area:: work] [priority:: A]
- [ ] [area:: work] [priority:: A]

---

## Tasks Captured Today



---

## Notes



---

## End of Day Reflection

**What went well?**


**What could be better?**


**Carry forward tomorrow:**

- [ ]
`;

const base64 = Buffer.from(content, 'utf-8').toString('base64');

return [{
  json: { fileKey, dateStr, dayName, focusTheme, created: true },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/markdown',
      fileName: `${dateStr}.md`
    }
  }
}];

const { dateStr, fileKey } = $('Compute Date & File Path').first().json;
console.log(`Daily note already exists for ${dateStr} — skipped`);
return [{ json: { skipped: true, dateStr, fileKey, message: `Note already exists: ${dateStr}.md` } }];

const item = $input.item.json;
console.log(`Daily Note Creator: ${item.message || (item.created ? 'Created' : 'Skipped')} ${item.dateStr}`);
return [{ json: { timestamp: new Date().toISOString(), ...item } }];
